def analyze_number(x):
    if x < 0:
        print("Line 1: Number is negative")
        if x < -10:
            print("Line 2: Number is less than -10")
    elif x == 0:
        print("Line 3: Number is zero")
    else:  # x > 0
        print("Line 4: Number is positive")
        if x > 10:
            print("Line 5: Number is greater than 10")
        if x % 2 == 0:
            print("Line 6: Number is even")
        else:
            print("Line 7: Number is odd")

# Call the function with the input value
analyze_number(x)

def approve_loan(income, credit_score, employed):
    if income < 30000:
        print("Line 1: Low income check")
        if credit_score >= 700:
            print("Line 2: Good credit despite low income")
            if employed:
                print("Line 3: Approved with conditions despite low income")
                return True
            else:
                print("Line 4: Rejected due to unemployment with low income")
                return False
        else:
            print("Line 5: Rejected due to low income and poor credit")
            return False
    else:
        print("Line 6: Sufficient income")
        if credit_score < 650:
            print("Line 7: Poor credit despite good income")
            if employed:
                print("Line 8: Approved with conditions despite poor credit")
                return True
            else:
                print("Line 9: Rejected due to unemployment and poor credit")
                return False
        else:
            print("Line 10: Good credit and income")
            print("Line 11: Fully approved")
            return True

# Call the function with the input values
result = approve_loan(income, credit_score, employed)
print(f"Final decision: {'Approved' if result else 'Rejected'}")
